import{c as e,a7 as r,y as a,B as n}from"./chunks/framework.3cjvm90C.js";const g=JSON.parse('{"title":"计算机专业学习路线","description":"计算机专业系统学习路线与课程推荐","frontmatter":{"title":"计算机专业学习路线","description":"计算机专业系统学习路线与课程推荐"},"headers":[],"relativePath":"toolbox/study/cs_class.md","filePath":"toolbox/study/cs_class.md","lastUpdated":1782448598000}'),l={name:"toolbox/study/cs_class.md"};function d(o,t,s,i,h,p){return r(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="计算机专业学习路线" tabindex="-1">计算机专业学习路线 <a class="header-anchor" href="#计算机专业学习路线" aria-label="Permalink to “计算机专业学习路线”">​</a></h1><h2 id="课程学习进度" tabindex="-1">课程学习进度 <a class="header-anchor" href="#课程学习进度" aria-label="Permalink to “课程学习进度”">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">课程</th><th style="text-align:center;">课程网站</th><th style="text-align:center;">B 站</th><th style="text-align:center;">难度系数</th><th>进度</th></tr></thead><tbody><tr><td style="text-align:center;">计算机科学速成课</td><td style="text-align:center;">-</td><td style="text-align:center;"><a href="https://www.bilibili.com/video/BV1EW411u7th" target="_blank" rel="noreferrer">学习</a></td><td style="text-align:center;">入门</td><td></td></tr><tr><td style="text-align:center;">数据结构与算法</td><td style="text-align:center;"><a href="https://the-algorithms.com/" target="_blank" rel="noreferrer">The Algorithms</a></td><td style="text-align:center;"></td><td style="text-align:center;">中等</td><td></td></tr><tr><td style="text-align:center;">算法导论</td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;">中等</td><td></td></tr><tr><td style="text-align:center;">计算机系统</td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;">难</td><td></td></tr><tr><td style="text-align:center;">操作系统</td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;">难</td><td></td></tr><tr><td style="text-align:center;">计算机网络</td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;">难</td><td></td></tr><tr><td style="text-align:center;">编译器</td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;">难</td><td></td></tr><tr><td style="text-align:center;">分布式计算</td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;">深入</td><td></td></tr></tbody></table><h2 id="自学计算机科学" tabindex="-1">自学计算机科学 <a class="header-anchor" href="#自学计算机科学" aria-label="Permalink to “自学计算机科学”">​</a></h2><p>如果你是一个自学成才的工程师，或者从编程培训班毕业，那么你很有必要学习计算机科学。幸运的是，不必为此花上数年光阴和不菲费用去攻读一个学位：仅仅依靠自己，你就可以获得世界一流水平的教育💸。</p><p>互联网上，到处都有许多的学习资源，然而精华与糟粕并存。你所需要的，不是一个诸如「200+ 免费在线课程」的清单，而是以下问题的答案：</p><ul><li>你应当学习 <strong>哪些科目</strong>，为什么？</li><li>对于这些科目，<strong>最好的书籍或者视频课程</strong> 是什么？</li></ul><p>在这份指引中，我们尝试对这些问题做出确定的回答。</p><p>大致按照列出的顺序，借助我们所建议的教材或者视频课程（但是最好二者兼用），学习如下的九门科目。目标是先花 100 到 200 个小时学习完每一个科目，然后在你职业生涯中，不时温习其中的精髓🚀。</p><table tabindex="0"><thead><tr><th>科目</th><th>为何要学？</th><th>最佳书籍</th><th>最佳视频</th></tr></thead><tbody><tr><td><a href="#编程">编程</a></td><td>不要做一个「永远没彻底搞懂」诸如递归等概念的程序员。</td><td><a href="https://book.douban.com/subject/1148282/" target="_blank" rel="noreferrer">《计算机程序的构造和解释》</a></td><td>Brian Harvey ’s Berkeley CS 61A</td></tr><tr><td><a href="#计算机系统结构">计算机系统结构</a></td><td>如果你对于计算机如何工作没有具体的概念，那么你所做出的所有高级抽象都是空中楼阁。</td><td><a href="https://book.douban.com/subject/26912767/" target="_blank" rel="noreferrer">《深入理解计算机系统》</a></td><td>Berkeley CS 61C</td></tr><tr><td><a href="#算法和数据结构">算法与数据结构</a></td><td>如果你不懂得如何使用栈、队列、树、图等常见数据结构，遇到有难度的问题时，你将束手无策。</td><td><a href="https://book.douban.com/subject/4048566/" target="_blank" rel="noreferrer">《算法设计手册》</a></td><td>Steven Skiena ’s lectures</td></tr><tr><td><a href="#数学知识">数学知识</a></td><td>计算机科学基本上是应用数学的一个「跑偏的」分支，因此学习数学将会给你带来竞争优势。</td><td><a href="https://book.douban.com/subject/33396340/" target="_blank" rel="noreferrer">《计算机科学中的数学》</a></td><td>Tom Leighton ’s MIT 6.042J</td></tr><tr><td><a href="#操作系统">操作系统</a></td><td>你所写的代码，基本上都由操作系统来运行，因此你应当了解其运作的原理。</td><td><a href="https://book.douban.com/subject/33463930/" target="_blank" rel="noreferrer">《操作系统导论》</a></td><td>Berkeley CS 162</td></tr><tr><td><a href="#计算机网络">计算机网络</a></td><td>互联网已然势不可挡：理解工作原理才能解锁全部潜力。</td><td><a href="https://book.douban.com/subject/30280001/" target="_blank" rel="noreferrer">《计算机网络：自顶向下方法》</a></td><td>Stanford CS 144</td></tr><tr><td><a href="#数据库">数据库</a></td><td>对于多数重要程序，数据是其核心，然而很少人理解数据库系统的工作原理。</td><td><em><a href="https://book.douban.com/subject/2256069/" target="_blank" rel="noreferrer">Readings in Database Systems</a></em> （暂无中译本）</td><td>Joe Hellerstein ’s Berkeley CS 186</td></tr><tr><td><a href="#编程语言与编译器">编程语言与编译器</a></td><td>若你懂得编程语言和编译器如何工作，你就能写出更好的代码，更轻松地学习新的编程语言。</td><td><em><a href="https://craftinginterpreters.com/" target="_blank" rel="noreferrer">Crafting Interpreters</a></em></td><td>Alex Aiken ’s course on Lagunita</td></tr><tr><td><a href="#分布式系统">分布式系统</a></td><td>如今，<strong>多数</strong> 系统都是分布式的。</td><td><a href="https://book.douban.com/subject/30329536/" target="_blank" rel="noreferrer">《数据密集型应用系统设计》</a></td><td>MIT 6.824</td></tr></tbody></table><h3 id="计算机系统" tabindex="-1">计算机系统 <a class="header-anchor" href="#计算机系统" aria-label="Permalink to “计算机系统”">​</a></h3><p>参考课程：华盛顿大学<a href="http://courses.cs.washington.edu/courses/cse351/" target="_blank" rel="noreferrer">CSE351: The Hardware/Software Interface</a></p><p>参考书籍：<a href="http://product.dangdang.com/24106647.html" target="_blank" rel="noreferrer">深入理解计算机系统(CSAPP)</a></p><p>参考视频： B 站 <a href="https://www.bilibili.com/video/BV1Zt411s7Gg" target="_blank" rel="noreferrer">Washington CSE351 2017</a></p><p>产出目标：完成<a href="http://csapp.cs.cmu.edu/3e/labs.html" target="_blank" rel="noreferrer">CSAPP 书籍配套的所有 Labs</a></p><p>挑战难度： 4 星</p><p>这门课程是系统编程基础，也是后续操作系统/网络/数据库/编译等课程的基础，相关内容是通向系统架构师的基本功。这门课比较贴近企业实战，对动手能力要求很高，课程一大目标是要程序员写出对机器友好的高性能代码。</p><h3 id="数据结构" tabindex="-1">数据结构 <a class="header-anchor" href="#数据结构" aria-label="Permalink to “数据结构”">​</a></h3><p>参考课程：伯克利大学<a href="https://sp19.datastructur.es/" target="_blank" rel="noreferrer">CS61B Data Structures</a></p><p>参考书籍： Head First Java + 数据结构书自选</p><p>参考视频： B 站 <a href="https://www.bilibili.com/video/BV1EJ411n72e" target="_blank" rel="noreferrer">UCB CS 61B Data Structures</a></p><p>产出目标：完成 CS 61B 站点上的所有 Labs/Homeworks/Projects。</p><p>挑战难度： 4 星</p><p>说明：数据结构的重要性毋庸置疑，伯克利的 CS 课程都是比较偏向实战型工程师的，纯理论的东西相对少。本课的重点是树立抽象编程思维，务必完成所有 Labs/Homeworks/Projects。</p><h3 id="操作系统" tabindex="-1">操作系统 <a class="header-anchor" href="#操作系统" aria-label="Permalink to “操作系统”">​</a></h3><p>参考课程：麻省理工 MIT 6.828 <a href="https://pdos.csail.mit.edu/6.828/2018/index.html" target="_blank" rel="noreferrer">Operating System Engineering</a></p><p>参考书籍：<a href="http://product.dangdang.com/27882546.html" target="_blank" rel="noreferrer">操作系统导论(Operating Systems: Three Easy Pieces)</a></p><p>参考视频： B 站 <a href="https://www.bilibili.com/video/av47977122" target="_blank" rel="noreferrer">HMC CS 134 2019 Operating System</a></p><p>产出目标：完成 MIT 6.828 站点上的所有 7 个 Labs</p><p>挑战难度： 5 星</p><p>说明： 6.828 是 MIT 的神课，这门课难度不小，含金量也不小。如果能完成所有实验，对操作系统的认识会有质的飞跃。</p><h3 id="计算机网络" tabindex="-1">计算机网络 <a class="header-anchor" href="#计算机网络" aria-label="Permalink to “计算机网络”">​</a></h3><p>参考课程：斯坦福 <a href="https://cs144.github.io/" target="_blank" rel="noreferrer">CS 144 Introduction to Computer Networking</a></p><p>参考书籍：<a href="http://product.dangdang.com/25299722.html" target="_blank" rel="noreferrer">计算机网络：自顶向下方法</a></p><p>参考视频： B 站 <a href="https://www.bilibili.com/video/BV137411Z7LR" target="_blank" rel="noreferrer">斯坦福大学： CS144 计算机网络介绍</a></p><p>产出目标：完成 CS 144 站点上的所有 8 个 Labs。</p><p>挑战难度： 4 星</p><p>说明：计算机网络知识和技能，是互联网应用开发的基础，也是成为系统架构师的基础。这门 CS 144 和配套书《计算机网络：自顶向下方法》，是目前最佳的学习计算机网络基础的课程和参考书。这也是一门投入产出比比较</p><h3 id="编译原理" tabindex="-1">编译原理 <a class="header-anchor" href="#编译原理" aria-label="Permalink to “编译原理”">​</a></h3><p>参考书籍：<a href="https://www.craftinginterpreters.com/contents.html" target="_blank" rel="noreferrer">Crafting Interpreters</a> 或者 <a href="https://www.amazon.com/Writing-Interpreter-Go-Thorsten-Ball/dp/3982016118" target="_blank" rel="noreferrer">Write an Interpreter in Go</a></p><p>参考视频： B 站 <a href="https://www.bilibili.com/video/BV1cE411f78c" target="_blank" rel="noreferrer">CS143 斯坦福编译原理</a></p><p>产出目标：参考<a href="https://github.com/munificent/craftinginterpreters" target="_blank" rel="noreferrer">Crafting Interpreters</a>，使用 Java 或者 golang 语言(或其它你熟悉的语言)，实现 Lox 小型编程语言。</p><p>或者，参考<a href="https://interpreterbook.com/" target="_blank" rel="noreferrer">Write an Interpreter in Go</a>，或<a href="https://compilerbook.com/" target="_blank" rel="noreferrer">Write A Compiler in Go</a>，使用 Java 语言实现 Monkey 小型语言。</p><p>挑战难度： 5 星</p><p>说明：视频可以不看，但是一定要自己动手实现一个小语言解释器或者编译器。</p><h3 id="数据库系统" tabindex="-1">数据库系统 <a class="header-anchor" href="#数据库系统" aria-label="Permalink to “数据库系统”">​</a></h3><p>参考课程：卡耐基梅隆 CMU <a href="https://15445.courses.cs.cmu.edu/fall2020/" target="_blank" rel="noreferrer">15-445/645 Database Systems</a></p><p>参考书籍：<a href="http://product.dangdang.com/22632572.html" target="_blank" rel="noreferrer">数据库系统概念</a></p><p>参考视频： B 站 <a href="https://www.bilibili.com/video/BV1Cp4y1C7dv" target="_blank" rel="noreferrer">卡耐基梅隆大学 15-445 数据库系统介绍</a></p><p>产出目标：参考<a href="https://github.com/vanilladb/vanillacore" target="_blank" rel="noreferrer">vanilladb 项目</a>，使用 golang 语言实现 clone 版的 vanilladb （原项目是 Java 实现的）。</p><p>挑战难度： 5 星</p><p>说明：视频/课程/书可以不看，但是一定要自己动手实现一个小型的数据库系统，包括服务器端的存储引擎、SQL 解析器、查询引擎和 JDBC 访问接口。企业开发大部分是基于数据库的应用，如果要成为企业级架构师，必须对数据库底层实现有一定掌握。课程项目要求用 golang，对 golang 语言不熟悉的，自己找资料自学，如果你按照课程计划坚持学到这门课，那么你已经具有足够基础，可以轻松 pick up 任何一门编程语言。</p><h2 id="参考网站" tabindex="-1">参考网站 <a class="header-anchor" href="#参考网站" aria-label="Permalink to “参考网站”">​</a></h2><ul><li><p><a href="https://teachyourselfcs.com/" target="_blank" rel="noreferrer">https://teachyourselfcs.com/</a></p></li><li><p><a href="https://github.com/izackwu/TeachYourselfCS-CN" target="_blank" rel="noreferrer">https://github.com/izackwu/TeachYourselfCS-CN</a></p></li><li><p><a href="https://hackway.org/docs/cs/intro" target="_blank" rel="noreferrer">https://hackway.org/docs/cs/intro</a></p></li><li><p><a href="https://github.com/spring2go/cs_study_plan" target="_blank" rel="noreferrer">https://github.com/spring2go/cs_study_plan</a></p></li></ul>',54)])])}const b=e(l,[["render",d]]);export{g as __pageData,b as default};
